parameters.functionCode:
const body = $input.first().json.body;
const data = body.data || body;

const now = body.event_timestamp ? new Date(body.event_timestamp * 1000) : new Date();
const sessionDate = now.toISOString().split('T')[0];
const sessionTime = now.toTimeString().split(' ')[0];
const durSecs = data.duration_seconds || 0;
const durFmt = Math.floor(durSecs / 60) + ':' + String(durSecs % 60).padStart(2, '0');

return [{
  json: {
    // Sesión / metadata
    session_id: data.conversation_id || 'N/A',
    employee_id: data.user_id || 'N/A',
    employee_name: data.agent_name || (data.dynamic_variables && data.dynamic_variables.user_name) || 'Empleado',
    department: 'VTC',
    session_date: sessionDate,
    session_time: sessionTime,
    scenario_desc: data.scenario_name || 'Standard',
    modules_practiced: data.modules_practiced || data.scenario_name || '',
    disc_type: data.disc_type || 'D',
    language: data.language || 'ES',
    duration_seconds: durSecs,
    duration_formatted: data.duration_formatted || durFmt,

    // Desempeño
    score: data.performance_score != null ? data.performance_score : 8,
    performance_summary: data.performance_note || 'Sesión completada',
    call_summary: data.call_summary || data.summary || '',
    sentiment: data.sentiment || 'neutral',
    interventions_count: data.interventions_count || 0,

    // Competencias (6 ejes)
    rapport_score: (data.competencies && data.competencies.rapport) || 8,
    pnl_score: (data.competencies && data.competencies.pnl) || 8,
    postura_score: (data.competencies && data.competencies.postura) || 8,
    objeciones_score: (data.competencies && data.competencies.objeciones) || 8,
    leer_sala_score: (data.competencies && data.competencies.leer_sala) || 8,
    cierre_score: (data.competencies && data.competencies.cierre) || 8,

    // Analisis
    neuro_principles: data.neuro_principles || '',
    what_went_well: data.strengths || 'Excelente desempeño',
    areas_to_improve: data.improvements || 'Continuar mejorando',
    objections_faced: data.objections || 'Ninguna',
    pnl_analysis: data.pnl_analysis || 'Análisis disponible',
    next_drill: data.next_drill || 'Próximo módulo',
    action_plan_items: data.action_plan || [],
    general_understanding: data.learning_score || null,
    participation_level: data.participation_level || '',
    deep_learning_notes: data.deep_learning_notes || '',
    session_activity: data.activity_summary || '',
    momentos_clave: data.timeline || data.momentos_clave || [],

    // Transcript completo palabra por palabra: [{speaker|role, t|time_in_call_secs, text|message}]
    transcript_items: data.transcript_items || data.transcript || [],

    // Audio + report links (permanent, conversation_id-keyed Vercel endpoints)
    audio_url: (data.conversation_id ? ('https://vtc-capacitacion-deploy.vercel.app/api/audio?conv=' + encodeURIComponent(data.conversation_id)) : (data.full_audio || data.audio_url || '')),
    report_url: (data.conversation_id ? ('https://vtc-capacitacion-deploy.vercel.app/api/report?conv=' + encodeURIComponent(data.conversation_id)) : 'https://vtc-capacitacion-deploy.vercel.app/'),
    pdf_url: (data.conversation_id ? ('https://vtc-capacitacion-deploy.vercel.app/api/report?conv=' + encodeURIComponent(data.conversation_id) + '&pdf=1') : ''),
  }
}];

