parameters.jsCode:
const item = $input.first();
const bin = item.binary || {};

let pdfBase64 = '';
let audioBase64 = '';

if (bin.pdf) {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'pdf');
  pdfBase64 = buf.toString('base64');
}
if (bin.audio) {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'audio');
  audioBase64 = buf.toString('base64');
}

const extract = $('Extract Data — 25 Fields').item.json;
const template = $('Template HTML Render').item.json;

const attachments = [
  {
    filename: 'reporte_' + extract.session_id + '.pdf',
    content: pdfBase64,
    contentType: 'application/pdf'
  },
  {
    filename: 'audio_' + extract.session_id + '.mp3',
    content: audioBase64,
    contentType: 'audio/mpeg'
  }
].filter(a => a.content && a.content.length > 0);

return [{
  json: {
    from: 'reportes@victor-ia.xyz',
    to: ['mesainteligentedemo@gmail.com'],
    cc: ['eldudemateos@gmail.com', 'chrisoria16@gmail.com'],
    subject: 'Reporte de Capacitación - ' + extract.employee_name,
    html: template.html,
    attachments,
    pdf_base64: pdfBase64,
    audio_base64: audioBase64,
    pdf_generated: Boolean(pdfBase64),
    audio_downloaded: Boolean(audioBase64)
  }
}];

